// ============================================================
// 🇨🇺 MOTOR DE BÚSQUEDA - EFEMÉRIDES Y FRASES COMBINADAS
// ============================================================

function buscarEfemeride(mes, dia) {
    const claveSinEspacio = `${mes}-${dia}`;
    const claveConEspacio = `${mes}-${dia} `;
    
    if (EFEMERIDES_CUBANAS[claveConEspacio]) return EFEMERIDES_CUBANAS[claveConEspacio].trim();
    if (EFEMERIDES_CUBANAS[claveSinEspacio]) return EFEMERIDES_CUBANAS[claveSinEspacio].trim();
    
    for (let key in EFEMERIDES_CUBANAS) {
        if (key.trim() === claveSinEspacio) {
            return EFEMERIDES_CUBANAS[key].trim();
        }
    }
    return null;
}

function buscarFrase(mes, dia) {
    const claveSinEspacio = `${mes}-${dia}`;
    const claveConEspacio = `${mes}-${dia} `;
    
    if (FRASES_CUBANAS[claveConEspacio]) return FRASES_CUBANAS[claveConEspacio].trim();
    if (FRASES_CUBANAS[claveSinEspacio]) return FRASES_CUBANAS[claveSinEspacio].trim();
    
    for (let key in FRASES_CUBANAS) {
        if (key.trim() === claveSinEspacio) {
            return FRASES_CUBANAS[key].trim();
        }
    }
    return null;
}

function obtenerContenidoCompleto(mes, dia) {
    const efemeride = buscarEfemeride(mes, dia);
    const frase = buscarFrase(mes, dia);
    
    let contenido = '';
    
    if (efemeride) {
        contenido += `<div style="margin-bottom: 10px; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 10px;">
            <div style="font-size: 11px; color: #cf142b; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px;">📜 EFEMÉRIDE DEL DÍA</div>
            <div style="font-size: 14px; line-height: 1.6; color: #e2e8f0;">${efemeride}</div>
        </div>`;
    }
    
    if (frase) {
        contenido += `<div>
            <div style="font-size: 11px; color: #f5c842; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px;">💬 CITA DEL DÍA</div>
            <div style="font-size: 14px; line-height: 1.6; color: #e8d8f0; font-style: italic;">"${frase}"</div>
        </div>`;
    }
    
    return contenido || '<div style="color: #8bb8e8; text-align: center;">No hay contenido disponible para hoy</div>';
}

