// Función para ocultar la campana
function ocultarCampana() {
    const campana = document.getElementById('armytage-bell-notification');
    if (campana) {
        campana.style.transition = 'all 0.4s ease';
        campana.style.opacity = '0';
        campana.style.transform = 'scale(0.5)';
        setTimeout(() => {
            if (campana.parentNode) {
                campana.remove();
            }
        }, 400);
    }
}

// Función para mostrar el toast completo (efeméride + frase)
function mostrarToastCompleto() {
    const hoy = new Date();
    const mes = hoy.getMonth() + 1;
    const dia = hoy.getDate();
    
    const contenido = obtenerContenidoCompleto(mes, dia);
    const fechaFormateada = hoy.toLocaleDateString('es-ES', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    });
    
    // Verificar si hay contenido real
    if (contenido.includes('No hay contenido disponible para hoy')) {
        mostrarToast('📅', fechaFormateada.toUpperCase(), contenido);
        return;
    }
    
    mostrarToast('🇨🇺', fechaFormateada.toUpperCase(), contenido);
}

// Función para crear y mostrar el toast
function mostrarToast(icono, titulo, contenido) {
    if (toastActual) {
        cerrarToast();
    }
    
    if (timeoutToast) {
        clearTimeout(timeoutToast);
        timeoutToast = null;
    }
    
    const toast = document.createElement('div');
    toast.id = 'armytage-toast-efemeride';
    toast.style.cssText = `
        position: fixed !important;
        top: 80px !important;
        right: 20px !important;
        z-index: 2147483647 !important;
        max-width: 400px !important;
        width: 92% !important;
        background: linear-gradient(145deg, #002a5c 0%, #001533 100%) !important;
        color: #ffffff !important;
        padding: 18px 22px !important;
        border-radius: 14px !important;
        box-shadow: 0 15px 50px rgba(0, 0, 0, 0.7), 0 0 0 1px rgba(255, 255, 255, 0.06) !important;
        font-family: system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif !important;
        border-left: 5px solid #cf142b !important;
        border-top: 1px solid rgba(255, 255, 255, 0.05) !important;
        opacity: 0;
        transform: translateX(50px) scale(0.9);
        transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
        pointer-events: auto !important;
        max-height: 85vh !important;
    `;
    
    toast.innerHTML = `
        <div style="display: flex !important; align-items: flex-start !important; gap: 14px !important;">
            <div style="font-size: 30px; flex-shrink: 0; margin-top: 2px;">${icono}</div>
            <div style="flex: 1; min-width: 0;">
                <div style="font-size: 11px; color: #8bb8e8; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px;">
                    ${titulo}
                </div>
                <div class="armytage-toast-scroll" style="
                    font-size: 13px; 
                    line-height: 1.7; 
                    color: #e2e8f0; 
                    max-height: 55vh; 
                    overflow-y: auto; 
                    padding-right: 4px;
                ">
                    ${contenido}
                </div>
            </div>
            <button id="armytage-toast-close-btn" style="
                background: rgba(255,255,255,0.06);
                border: none;
                color: #8bb8e8;
                font-size: 18px;
                cursor: pointer;
                padding: 4px 10px;
                border-radius: 8px;
                flex-shrink: 0;
                transition: all 0.2s ease;
                line-height: 1;
                font-family: system-ui, sans-serif;
            ">✕</button>
        </div>
        <div style="
            position: absolute;
            bottom: 0;
            left: 0;
            height: 3px;
            background: linear-gradient(90deg, #cf142b, #e8344c, #f5c842);
            width: 100%;
            animation: armytageToastProgress 10s linear forwards;
            border-radius: 0 0 0 14px;
        "></div>
    `;
    
    if (!document.getElementById('armytage-toast-progress-styles')) {
        const styleProgress = document.createElement('style');
        styleProgress.id = 'armytage-toast-progress-styles';
        styleProgress.textContent = `
            @keyframes armytageToastProgress {
                0% { width: 100%; }
                100% { width: 0%; }
            }
        `;
        document.head.appendChild(styleProgress);
    }
    
    document.body.appendChild(toast);
    toastActual = toast;
    notificacionActiva = true;
    
    requestAnimationFrame(() => {
        toast.style.opacity = '1';
        toast.style.transform = 'translateX(0) scale(1)';
    });
    
    const closeBtn = document.getElementById('armytage-toast-close-btn');
    if (closeBtn) {
        closeBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            cerrarToast();
        });
    }
    
    toast.addEventListener('click', function(e) {
        if (e.target.id === 'armytage-toast-close-btn') return;
        cerrarToast();
    });
    
    timeoutToast = setTimeout(() => {
        cerrarToast();
    }, 10000);
    
    const escHandler = function(e) {
        if (e.key === 'Escape') {
            cerrarToast();
            document.removeEventListener('keydown', escHandler);
        }
    };
    document.addEventListener('keydown', escHandler);
    
    const campana = document.getElementById('armytage-bell-notification');
    if (campana) {
        campana.style.opacity = '0.3';
        campana.style.transform = 'scale(0.8)';
    }
}

// Función para cerrar el toast
function cerrarToast() {
    if (toastActual) {
        toastActual.style.opacity = '0';
        toastActual.style.transform = 'translateX(50px) scale(0.9)';
        setTimeout(() => {
            if (toastActual && toastActual.parentNode) {
                toastActual.remove();
            }
            toastActual = null;
            notificacionActiva = false;
            ocultarCampana();
        }, 400);
    }
    
    if (timeoutToast) {
        clearTimeout(timeoutToast);
        timeoutToast = null;
    }
}

// ============================================================
// 🛡️ CONTROL DE FRECUENCIA
// ============================================================
const ControlFrecuencia = {
    ultimaVez: 0,
    minIntervalo: 180000, // 3 minutos
    
    puedeMostrar: function() {
        const ahora = Date.now();
        if (ahora - this.ultimaVez > this.minIntervalo) {
            this.ultimaVez = ahora;
            return true;
        }
        return false;
    },
    
    registrarMostrado: function() {
        this.ultimaVez = Date.now();
        sessionStorage.setItem('efemeride_shown_session', 'true');
    }
};

// ============================================================
// 🚀 MÉTODOS DE ACTIVACIÓN
// ============================================================

function procesarYMostrarCompleto(motivo = 'carga') {
    if (motivo !== 'timer_50min' && sessionStorage.getItem('efemeride_shown_session') === 'true') {
        return;
    }

    if (!ControlFrecuencia.puedeMostrar() && motivo !== 'timer_50min') return;

    const hoy = new Date();
    const mes = hoy.getMonth() + 1;
    const dia = hoy.getDate();
    const efemeride = buscarEfemeride(mes, dia);
    const frase = buscarFrase(mes, dia);
    
    if (efemeride || frase) {
        mostrarCampana();
        ControlFrecuencia.registrarMostrado();
        console.log(`[CONTENIDO] Campana mostrada por: ${motivo}`);
    }
}

// --- MÉTODO 1: SCROLL PROFUNDO (25%) ---
let scrollActivado = false;
const scrollHandler = () => {
    if (scrollActivado) return;
    const scrollPorcentaje = (window.scrollY + window.innerHeight) / document.documentElement.scrollHeight;
    if (scrollPorcentaje > 0.25) {
        scrollActivado = true;
        procesarYMostrarCompleto('scroll_25%');
        window.removeEventListener('scroll', scrollHandler);
    }
};
window.addEventListener('scroll', scrollHandler, { passive: true });

// --- MÉTODO 2: INTENCIÓN DE SALIDA ---
let exitActivado = false;
document.addEventListener('mouseleave', (e) => {
    if (exitActivado || e.clientY > 0) return;
    exitActivado = true;
    procesarYMostrarCompleto('exit_intent');
}, { passive: true });

// --- MÉTODO 3: REGRESO A LA PESTAÑA ---
let tiempoAusencia = 0;
let intervaloAusencia = null;

document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'hidden') {
        tiempoAusencia = Date.now();
        if (intervaloAusencia) clearInterval(intervaloAusencia);
        intervaloAusencia = setInterval(() => {
            if (Date.now() - tiempoAusencia > 10000) {
                sessionStorage.removeItem('efemeride_shown_session');
            }
        }, 1000);
    } else {
        if (intervaloAusencia) {
            clearInterval(intervaloAusencia);
            intervaloAusencia = null;
        }
        if (Date.now() - tiempoAusencia > 10000) {
            procesarYMostrarCompleto('regreso_a_pestaña');
        }
    }
});

// --- MÉTODO 4: TIMER DE 50 MINUTOS ---
setInterval(() => {
    procesarYMostrarCompleto('timer_50min');
}, 3000000);

// ============================================================
// ⏰ INICIALIZACIÓN
// ============================================================

window.addEventListener('load', () => {
    setTimeout(() => {
        procesarYMostrarCompleto('carga_inicial');
    }, 2500);
});

document.addEventListener('armytage:usuarioRegistrado', () => {
    sessionStorage.removeItem('efemeride_shown_session');
    procesarYMostrarCompleto('registro_usuario');
});

console.log("🇨🇺 Sistema de Efemérides y Frases V6.0 - Campana Única cargado.");